    sa.Column('requested_date', postgresql.TIMESTAMP(), autoincrement=False, nullable=False),
    sa.Column('verified_date', postgresql.TIMESTAMP(), autoincrement=False, nullable=True),
    sa.Column('approved_date', postgresql.TIMESTAMP(), autoincrement=False, nullable=True),
